+package com.heafitmp.common.entity;
+
+import com.baomidou.mybatisplus.annotation.IdType;
+import com.baomidou.mybatisplus.annotation.TableId;
+import com.baomidou.mybatisplus.annotation.TableName;
+import lombok.Data;
+import java.time.LocalDateTime;
+
+@Data
+@TableName("fitting_session_devices")
+public class FittingSessionDevice {
+    @TableId(type = IdType.AUTO)
+    private Long id;
+    private String sessionId;      // 外键关联 FittingSession
+    private String ear;           // left / right
+    private String sn;            // 序列号（原始绑定值，烧录验证用）
+    private String materialNo;     // 物料号（原始绑定值，烧录验证用）
+    private String model;         // 型号
+    private byte[] audiogram;     // 听力图数据(66字节)
+    private LocalDateTime createdAt;
+    // 当前同步数据（心跳更新，验配师查看用，不参与烧录验证）
+    private String currentSn;
+    private String currentMaterialNo;
+}
