+    @PostMapping("/session/{sessionId}/send")
+    public ApiResponse<Map<String, Object>> sendFitting(
+            @PathVariable String sessionId,
+            @RequestBody Map<String, Object> params) {
+
+        String targetEar = (String) params.get("targetEar");
+        String type = (String) params.get("type");
+        Object data = params.get("data");
+
+        if (targetEar == null || targetEar.isEmpty()) {
+            return ApiResponse.error("targetEar不能为空");
+        }
+
+        // 检查是否有正在进行的操作（试听和烧录都需要锁定）
+        Map<String, Object> currentOp = operatingSessions.get(sessionId);
+        if (currentOp != null) {
+            String busyEar = (String) currentOp.get("targetEar");
+            String opType = (String) currentOp.get("type");
+            return ApiResponse.error((busyEar.equals("left") ? "左耳" : "右耳") + "正在" + ("trial".equals(opType) ? "试听" : "烧录") + "中，请等待");
+        }
+
+        // 查询目标耳朵的设备是否存在
+        List<FittingSessionDevice> devices = fittingSessionDeviceMapper.selectList(
+            new QueryWrapper<FittingSessionDevice>()
+                .eq("session_id", sessionId)
+                .eq("ear", targetEar)
+        );
+
+        if (devices.isEmpty()) {
+            return ApiResponse.error("用户未连接" + ("left".equals(targetEar) ? "左耳" : "右耳") + "设备");
+        }
+
+        FittingSessionDevice targetDevice = devices.get(0);
+
+        // 标记操作开始（试听和烧录都需要锁定）
+        operatingSessions.put(sessionId, Map.of(
+            "targetEar", targetEar,
+            "type", type != null ? type : "trial",
+            "startTime", System.currentTimeMillis()
+        ));
+
+        try {
+            // 构建消息内容，增加 targetEar 字段
+            Map<String, Object> messageData = new HashMap<>();
+            messageData.put("targetEar", targetEar);
+            messageData.put("deviceSn", targetDevice.getSn());
+            messageData.put("materialNo", targetDevice.getMaterialNo());
+            messageData.put("type", type);
+            if (data != null) {
+                messageData.put("data", data);
+            }
+
+            // 根据 type 决定消息类型
+            String msgType = "trial".equals(type) ? "trial_received" : "verification_required";
+
+            // 通过 WebSocket 发送
+            webSocketHandler.broadcastToSession(sessionId, msgType, messageData);
+
+            Map<String, Object> result = new HashMap<>();
+            result.put("success", true);
+            result.put("targetEar", targetEar);
+            return ApiResponse.success(result);
+        } catch (Exception e) {
+            // 发送失败时移除操作状态
+            operatingSessions.remove(sessionId);
+            throw e;
+        }
+    }
