package com.heafitmp.fitting.task;

import com.baomidou.mybatisplus.core.conditions.query.QueryWrapper;
import com.heafitmp.common.entity.FittingSession;
import com.heafitmp.fitting.mapper.FittingSessionMapper;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.scheduling.annotation.Scheduled;
import org.springframework.stereotype.Component;

import java.time.LocalDateTime;

@Component
public class SessionCleanupTask {

    @Autowired
    private FittingSessionMapper fittingSessionMapper;

    @Scheduled(fixedRate = 60000)
    public void cleanupExpiredSessions() {
        QueryWrapper<FittingSession> queryWrapper = new QueryWrapper<>();
        queryWrapper.eq("status", "waiting")
                .lt("expire_time", LocalDateTime.now());

        var expiredSessions = fittingSessionMapper.selectList(queryWrapper);
        if (expiredSessions.isEmpty()) {
            return;
        }

        for (FittingSession session : expiredSessions) {
            session.setStatus("closed");
            fittingSessionMapper.updateById(session);
            System.out.println("Expired session closed: " + session.getSessionId() + " (code: " + session.getCode() + ")");
        }

        System.out.println("Session cleanup completed: " + expiredSessions.size() + " sessions closed");
    }
}
